/*!40000 ALTER TABLE `faqs` DISABLE KEYS */;
INSERT INTO `faqs` VALUES (1,NULL,'What is ECDE?','ECDE (Early Childhood Development Education) refers to the foundational education programme for children aged 3–5 years, focusing on holistic development including cognitive, social, and physical growth.',1,'published','2026-05-13 13:53:24','2026-05-13 13:53:24'),(2,NULL,'Who manages ECDE centres in Laikipia County?','ECDE centres are managed by the County Government of Laikipia through the Department of Education.',2,'published','2026-05-13 13:53:56','2026-05-13 13:53:56'),(3,NULL,'Who employs ECDE teachers?','ECDE teachers are employed by the County Government of Laikipia.',3,'published','2026-05-13 13:54:45','2026-05-13 13:54:45'),(4,NULL,'Are ECDE services free in Laikipia County?','Most ECDE services are subsidized by the County Government, but some centres may charge minimal fees for meals or facilities.',4,'published','2026-05-13 13:55:18','2026-05-13 13:55:18'),(5,NULL,'Why was the ECDE-MIS introduced?','It was introduced to improve data accuracy, enhance planning, and support efficient service delivery across all ECDE centres.',5,'published','2026-05-13 13:55:44','2026-05-13 13:55:44'),(6,NULL,'Who uses the ECDE-MIS system?','The system is used by ECDE coordinators, head teachers, teachers, and county education officials.',6,'published','2026-05-13 13:56:09','2026-05-13 13:56:09'),(7,NULL,'How can I enroll my child in an ECDE centre?','You can enroll your child by visiting the nearest ECDE centre with the required documents such as a birth certificate.',7,'published','2026-05-13 13:56:52','2026-05-13 13:56:52'),(8,NULL,'What documents are required for enrollment?','Typically, a birth certificate and guardian details are required.',8,'published','2026-05-13 13:57:14','2026-05-13 13:57:14'),(9,NULL,'How does ECDE-MIS improve service delivery?','It enables real-time data access, helping the County make informed decisions and allocate resources effectively.',9,'published','2026-05-13 13:57:47','2026-05-13 13:57:47'),(10,NULL,'Who can access ECDE reports?','Access is granted to authorized county officials and education administrators.',10,'published','2026-05-13 13:58:15','2026-05-13 13:58:15');
/*!40000 ALTER TABLE `faqs` ENABLE KEYS */;
UNLOCK TABLES;

